('spanish:1-1-me-my-family-and-friends:mcq:21c94f7b', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Tengo quince años.\" data-listen></span><br>Listen. What is being said?", "options": ["I am fifteen years old", "I have fifteen euros", "There are fifteen of us at home", "I am fifty years old"]}'::jsonb, '{"answer": 0, "explain": "‘tengo quince años’ = I am 15 (literally ‘I have 15 years’). Traps play on ‘tengo’ and the number."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:91cc195b', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Tengo el pelo largo y castaño.\" data-listen></span><br>Listen. How is the hair described?", "options": ["long and brown", "short and black", "long and blond", "curly and grey"]}'::jsonb, '{"answer": 0, "explain": "largo = long, castaño = brown. The distractors swap one or both features."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:05bf57ee', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Mi hermano mayor lleva gafas.\" data-listen></span><br>Listen. Which is correct?", "options": ["My older brother wears glasses", "My younger brother has a beard", "My older sister wears glasses too", "My brother wants some new glasses"]}'::jsonb, '{"answer": 0, "explain": "hermano mayor = older brother; lleva gafas = wears glasses. Distractors change age, gender or add detail."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:03df0e1f', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "How do you say ‘I am 14 years old’?", "options": ["Tengo catorce años", "Soy catorce años", "Tengo catorce años de vida", "Estoy catorce años"]}'::jsonb, '{"answer": 0, "explain": "Age = tener: tengo catorce años. ‘Soy/Estoy’ are the classic English-speaker error."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:5557df88', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "Which is correct for ‘I have brown eyes’?", "options": ["Tengo los ojos marrones", "Tengo los ojos de color marrón", "Tengo los ojos marrón", "Soy los ojos marrones"]}'::jsonb, '{"answer": 0, "explain": "los ojos is plural → the colour agrees: marrones. ‘marrón’ singular does not agree; ‘soy’ is wrong."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:58a0e404', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "Complete: ‘___ hermanos son altos.’ (my brothers)", "options": ["Mis", "Sus", "Mi", "Tu"]}'::jsonb, '{"answer": 0, "explain": "The possessive agrees with the plural noun ‘hermanos’ → mis. ‘Sus’ would mean ‘their/his/her’."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:0f3be318', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "‘Soy hijo único’ means…", "options": ["I am an only child", "I am a unique person", "I am the eldest son", "I am someone''s only true friend"]}'::jsonb, '{"answer": 0, "explain": "hijo único = only child. (‘único’ here is ‘only’, not ‘unique’.)"}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:8bdee0b4', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "Complete: ‘___ el pelo rubio.’ (I have)", "options": ["Tengo", "Soy", "Está", "Llevo"]}'::jsonb, '{"answer": 0, "explain": "Hair uses tener → Tengo el pelo rubio."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:702b1a67', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "Why ‘Tengo 15 años’, not ‘Soy 15 años’?", "options": ["Spanish uses ‘tener’ (to have) for age", "‘ser’ can only describe your job", "you must always use ‘estar’ with numbers", "‘años’ has to follow the verb ‘ser’"]}'::jsonb, '{"answer": 0, "explain": "Age is expressed with tener in Spanish: you ‘have’ years."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:mcq:f239d8a5', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'mcq', 'mcq', 1, '{"question": "‘Mi hermana, que es alta, tiene el pelo rizado’ — what does ‘que’ do?", "options": ["links two ideas (‘who / that’)", "shows that it is a plan for the future", "turns it into a question", "means ‘because’"]}'::jsonb, '{"answer": 0, "explain": "Relative ‘que’ = who/that, joining ‘my sister’ + ‘she is tall’."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:tf:74a7e953', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'tf', 'tf', 1, '{"question": "For age, Spanish uses ‘tener’ — ‘tengo quince años’."}'::jsonb, '{"answer": true, "explain": "You literally ‘have’ years: tengo… años. ‘Soy… años’ is wrong."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:tf:b2b3db46', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'tf', 'tf', 1, '{"question": "Hair and eyes use ‘tener’: ‘tengo el pelo rubio’."}'::jsonb, '{"answer": true, "explain": "Spanish ‘has’ hair and eyes, and keeps the article (el/los)."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:tf:e503397e', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'tf', 'tf', 1, '{"question": "‘hijo único’ means ‘a unique son’."}'::jsonb, '{"answer": false, "explain": "It means ‘only child’ — único here = only."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:tf:91656729', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'tf', 'tf', 1, '{"question": "‘mis hermanos’ is correct because the possessive agrees with the plural noun."}'::jsonb, '{"answer": true, "explain": "mi → mis to match a plural noun (hermanos)."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:tf:d50d7fba', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'tf', 'tf', 1, '{"question": "‘mayor’ means ‘younger’."}'::jsonb, '{"answer": false, "explain": "mayor = older; menor = younger."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:tf:356ff3cb', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'tf', 'tf', 1, '{"question": "‘Tengo los ojos marrón’ is correct."}'::jsonb, '{"answer": false, "explain": "Eyes are plural, so the colour must agree: los ojos marrones."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:tf:dfc2869f', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'tf', 'tf', 1, '{"question": "‘llevar’ is used for glasses: ‘llevo gafas’."}'::jsonb, '{"answer": true, "explain": "llevar = to wear (glasses, clothes)."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:tf:68a216fc', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'tf', 'tf', 1, '{"question": "Build/height uses ‘ser’: ‘soy alto’."}'::jsonb, '{"answer": true, "explain": "ser describes what you are like: soy alto/alta."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:learn:533e17a0', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'learn', 'mcq', 1, '{"readingTitle": "How do I introduce myself?", "reading": "<p>The building blocks for talking about yourself — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"me llamo\">me llamo…</span></td><td>my name is…</td><td><span data-say=\"tengo catorce años\">tengo… años</span></td><td>I am … years old</td></tr>\n              <tr><td><span data-say=\"soy de\">soy de…</span></td><td>I am from…</td><td><span data-say=\"vivo en\">vivo en…</span></td><td>I live in…</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Me llamo Ana, tengo quince años y vivo en Madrid.\">Me llamo Ana, tengo quince años y vivo en Madrid.</span></p>\n            <p><strong>Big rule:</strong> for age Spanish uses <strong>tener</strong> (to have), not ‘ser’ — you literally ‘have’ years.</p>", "question": "How do you say ‘I am 15 years old’?", "options": ["Tengo quince años", "Soy quince años", "Estoy quince años", "Tengo quince año"]}'::jsonb, '{"answer": 0, "explain": "Age uses tener: ‘tengo quince años’ — never ‘soy’. ‘años’ is plural."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:learn:6995f9f0', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe how I look?", "reading": "<p>Use <strong>ser</strong> for build/height and <strong>tener</strong> for hair and eyes:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"soy alto\">soy alto / alta</span></td><td>I am tall</td><td><span data-say=\"soy bajo\">soy bajo / baja</span></td><td>I am short</td></tr>\n              <tr><td><span data-say=\"soy delgado\">soy delgado / delgada</span></td><td>I am slim</td><td><span data-say=\"llevo gafas\">llevo gafas</span></td><td>I wear glasses</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Soy alta y delgada, y llevo gafas.\">Soy alta y delgada, y llevo gafas.</span> <em>(alt<strong>a</strong>, delgad<strong>a</strong> — female.)</em></p>", "question": "Which verb describes hair and eyes — ‘tengo el pelo…’?", "options": ["tener (to have)", "ser (to be)", "estar (to be)", "llevar (to wear)"]}'::jsonb, '{"answer": 0, "explain": "Spanish ‘has’ hair and eyes: tengo el pelo…, tengo los ojos… ‘llevar’ is for glasses/clothes."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:learn:d10d98c1', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe my hair and eyes?", "reading": "<p>Use <strong>tengo el pelo…</strong> (I have … hair) and <strong>tengo los ojos…</strong> (I have … eyes). Note the article (‘el’, ‘los’) — Spanish keeps it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el pelo rubio\">el pelo rubio</span></td><td>blond hair</td><td><span data-say=\"el pelo moreno\">el pelo moreno</span></td><td>dark hair</td></tr>\n              <tr><td><span data-say=\"el pelo castaño\">el pelo castaño</span></td><td>brown hair</td><td><span data-say=\"corto o largo\">corto / largo</span></td><td>short / long</td></tr>\n              <tr><td><span data-say=\"los ojos azules\">los ojos azules</span></td><td>blue eyes</td><td><span data-say=\"los ojos marrones\">los ojos marrones</span></td><td>brown eyes</td></tr>\n            </table>\n            <p>Colours agree: eyes are plural, so <span data-say=\"Tengo los ojos verdes.\">Tengo los ojos verdes.</span></p>", "question": "How do you say ‘I have long hair’?", "options": ["Tengo el pelo largo", "Llevo el pelo largo casi siempre", "Soy el pelo largo", "Tengo el pelo larga"]}'::jsonb, '{"answer": 0, "explain": "Hair uses tener + the article ‘el’; ‘pelo’ is masculine so the colour/length agrees: largo (not larga)."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:learn:6f0a12a8', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'learn', 'mcq', 1, '{"readingTitle": "Who is in my family?", "reading": "<p>Family members (<strong>la familia</strong>):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"los padres\">los padres</span></td><td>parents</td><td><span data-say=\"los abuelos\">los abuelos</span></td><td>grandparents</td></tr>\n              <tr><td><span data-say=\"el hermano mayor\">el hermano mayor</span></td><td>older brother</td><td><span data-say=\"la hermana menor\">la hermana menor</span></td><td>younger sister</td></tr>\n              <tr><td><span data-say=\"el tío\">el tío / la tía</span></td><td>uncle / aunt</td><td><span data-say=\"el primo\">el primo / la prima</span></td><td>cousin</td></tr>\n            </table>\n            <p><span data-say=\"Soy hijo único.\">Soy hijo único.</span> = I’m an only child. <span data-say=\"En mi familia hay cuatro personas.\">En mi familia hay cuatro personas.</span></p>", "question": "What does ‘mi hermana menor’ mean?", "options": ["my younger sister", "my older sister", "my younger brother", "my cousin"]}'::jsonb, '{"answer": 0, "explain": "hermana = sister; menor = younger. mayor = older."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:learn:fc1625a0', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'learn', 'mcq', 1, '{"readingTitle": "How do I say ‘my’ and ‘your’? (possessives)", "reading": "<p>Possessive adjectives agree with the <strong>number</strong> of the thing owned (one or many), NOT with you:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mi hermano\">mi</span> (one thing)</td><td>my — <span data-say=\"mi hermano\">mi hermano</span></td></tr>\n              <tr><td><span data-say=\"mis hermanos\">mis</span> (more than one)</td><td>my — <span data-say=\"mis hermanos\">mis hermanos</span></td></tr>\n              <tr><td><span data-say=\"tu casa\">tu / tus</span></td><td>your — tu casa, tus amigos</td></tr>\n              <tr><td><span data-say=\"su perro\">su / sus</span></td><td>his / her / their</td></tr>\n            </table>\n            <p>So it’s <strong>mi</strong> hermano but <strong>mis</strong> hermanos — the ‑s matches the plural noun.</p>", "question": "How do you say ‘my brothers’ (more than one)?", "options": ["mis hermanos", "mi hermanos", "mío hermanos", "mis hermano"]}'::jsonb, '{"answer": 0, "explain": "The possessive agrees with the plural noun: mis hermanos."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:learn:92d900cc', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'learn', 'mcq', 1, '{"readingTitle": "Higher: longer, richer descriptions", "reading": "<p><span class=\"tier-h\">H</span> Add quantifiers and join clauses to describe more precisely:</p>\n            <ul>\n              <li>Quantifiers: <span data-say=\"bastante alto\">bastante alto</span> (quite tall), <span data-say=\"un poco tímido\">un poco tímido</span> (a bit shy). <span class=\"tier-h\">H</span></li>\n              <li>Relative ‘que’: <span data-say=\"Tengo un hermano que se llama Luis.\">Tengo un hermano que se llama Luis.</span> <span class=\"tier-h\">H</span></li>\n              <li>Combine appearance + who: <span data-say=\"Mi hermana mayor, que es muy alta, tiene el pelo largo y rizado.\">Mi hermana mayor, que es muy alta, tiene el pelo largo y rizado.</span> <span class=\"tier-h\">H</span></li>\n            </ul>", "question": "‘Tengo un hermano que se llama Luis’ — what does ‘que’ do here?", "options": ["it links two ideas (‘who’ / ‘that’)", "it is used to ask a question meaning ‘what?’", "it means ‘because’", "it makes the sentence a plan"]}'::jsonb, '{"answer": 0, "explain": "Relative ‘que’ = who/that; it joins ‘I have a brother’ + ‘he is called Luis’."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:misc:f87d6ef2', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Soy quince años.</p><p><strong>✅ The correct idea:</strong> Tengo quince años.</p>", "question": "Why ‘Tengo quince años’, not ‘Soy…’?", "options": ["Spanish expresses age with ‘tener’ (to have)", "‘ser’ can only ever be used with jobs", "you must put the number after the verb ‘ser’", "age always needs the verb ‘estar’ instead"]}'::jsonb, '{"answer": 0, "explain": "In Spanish you ‘have’ years: tengo… años."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:misc:2faa9b22', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Tengo ojos azul.</p><p><strong>✅ The correct idea:</strong> Tengo los ojos azules.</p>", "question": "What is wrong with ‘Tengo ojos azul’?", "options": ["needs ‘los’ and the plural colour ‘azules’", "the verb here should really be ‘soy’ and not ‘tengo’", "‘ojos’ must be written in the singular", "you must add an accent to ‘azul’"]}'::jsonb, '{"answer": 0, "explain": "Keep the article ‘los’ and agree the colour in the plural: los ojos azules."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:misc:fda2c00e', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mis hermano es alto.</p><p><strong>✅ The correct idea:</strong> Mi hermano es alto.</p>", "question": "Why ‘Mi hermano’, not ‘Mis hermano’?", "options": ["‘hermano’ is singular, so the possessive is ‘mi’", "the possessive always agrees with the person who is speaking", "you always use ‘mis’ before a family word", "‘hermano’ must become plural after ‘mis’"]}'::jsonb, '{"answer": 0, "explain": "The possessive matches the noun: one hermano → mi; many → mis."}'::jsonb),
('spanish:1-1-me-my-family-and-friends:misc:af3129d9', 'spanish', 'spanish:1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> único = unique (only meaning)</p><p><strong>✅ The correct idea:</strong> hijo único = only child</p>", "question": "In ‘hijo único’, what does ‘único’ mean?", "options": ["only (an only child)", "unique, exactly as in English", "the youngest of the family", "a lonely or sad child"]}'::jsonb, '{"answer": 0, "explain": "hijo único = only child; único here = only, not ‘unique’."}'::jsonb),
