('spanish:1-2-relationships-and-role-models:misc:7f689b74', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mi hermano está gracioso.</p><p><strong>✅ The correct idea:</strong> Mi hermano es gracioso.</p>", "question": "Why ‘es’, not ‘está’, for ‘funny’?", "options": ["a personality trait is permanent → ser", "you must always use ‘tener’ with people", "‘gracioso’ is a plural adjective", "‘estar’ only works in the past"]}'::jsonb, '{"answer": 0, "explain": "Permanent personality traits use ser; estar would suggest a temporary state."}'::jsonb),
