('spanish:1-2-relationships-and-role-models:tips:ef802bcc', 'spanish', 'spanish:1-2-relationships-and-role-models', '1.2 Relationships and Role Models', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Dictation (listening)", "reading": "Listen for the little words that flip the meaning: ‘bien’ vs ‘mal’ (get on well vs badly), ‘con’ (with), ‘pero’ (but). And catch adjective endings — ‑o or ‑a tells you if it’s about a male or a female.", "question": "You hear ‘me llevo mal con…’. What does ‘mal’ tell you?", "options": ["they get on badly", "they get on very well", "nobody was mentioned", "it happened in the past"]}'::jsonb, '{"answer": 0, "explain": "mal = badly, so ‘me llevo mal con’ = I get on badly with."}'::jsonb),
